mapper.select:
select t.* from (

where 1=1

${params.dataScope}
and tas.deal_flag = #{dealFlag}
and tas.alert_type = #{alertType}
and tas.building_id = #{buildingId}
and tas.floor_id = #{floorId}
and bpi.block = #{block}
and bpi.zone = #{zone}
and bpi.zone_sub = #{zoneSub}
and DATE_FORMAT(tas.create_time,'%Y-%m-%d') = STR_TO_DATE(#{createTime},
    '%Y-%m-%d')

and DATE_FORMAT(tas.create_time,'%Y-%m-%d')  >= 
    STR_TO_DATE(#{createTimeStart},
    '%Y-%m-%d')

and DATE_FORMAT(tas.create_time,'%Y-%m-%d')  <= 
    STR_TO_DATE(#{createTimeEnd},
    '%Y-%m-%d')

order by

    CASE
    WHEN tas.alert_type=#{checkAlertType} THEN 1
    ELSE 2
    END,

tas.deal_flag asc, tas.create_time desc) t


where ter_sn = #{terSn}

    and alert_type = #{alertType}


    and sensor_type = #{sensorType}

order by create_time desc limit 1

mapper.update:
update ter_alert_system
ter_sn = #{terSn}, sensor_type = #{sensorType}, alert_type = #{alertType}, create_time = #{createTime}, deal_time = #{dealTime}, del_flag = #{delFlag}, deal_flag = #{dealFlag},
where id = #{id}
